const GUEST_TOKEN_SECRET = process.env.ADMIN_PASSWORD
  ? crypto.createHash('sha256').update('mcc-guest-split-' + process.env.ADMIN_PASSWORD).digest('hex')
  : null;

if (!GUEST_TOKEN_SECRET) {
  console.warn('[Security] ADMIN_PASSWORD not set — split-payment guest links are disabled.');
}

function generateGuestToken(participantId) {
  if (!GUEST_TOKEN_SECRET) return null;
  return crypto.createHmac('sha256', GUEST_TOKEN_SECRET).update(participantId).digest('hex').substring(0, 32);
}

function verifyGuestToken(participantId, token) {
  if (!GUEST_TOKEN_SECRET) return false;
  if (!token || token.length !== 32) return false;
  try {
    return crypto.timingSafeEqual(
      Buffer.from(token, 'utf8'),
      Buffer.from(generateGuestToken(participantId), 'utf8')
    );
  } catch {
    return false;
  }
}

// ========== RATE LIMITING ==========

const rateLimitStore = new Map();

const rateLimitConfig = {
  login: { limit: 5, windowMs: 60000 },
  sms2fa: { limit: 3, windowMs: 60000 },
  apiAuth: { limit: 100, windowMs: 60000 },
  public: { limit: 30, windowMs: 60000 },
  adminVerify: { limit: 10, windowMs: 60000 },
  helpdesk: { limit: 10, windowMs: 60000 }
};

function getClientIP(req) {
  const forwarded = req.headers['x-forwarded-for'];
  if (forwarded) {
    return forwarded.split(',')[0].trim();
  }
  return req.socket?.remoteAddress || req.connection?.remoteAddress || 'unknown';
}

function checkRateLimit(identifier, limit, windowMs) {
  const now = Date.now();
  const key = identifier;
  
  let entry = rateLimitStore.get(key);
  
  if (!entry || entry.resetTime <= now) {
    entry = {
      count: 1,
      resetTime: now + windowMs
    };
    rateLimitStore.set(key, entry);
    return {
      allowed: true,
      remaining: limit - 1,
      resetTime: entry.resetTime
    };
  }
  
  entry.count++;
  
  if (entry.count > limit) {
    return {
      allowed: false,
      remaining: 0,
      resetTime: entry.resetTime
    };
  }
  
  return {
    allowed: true,
    remaining: limit - entry.count,
    resetTime: entry.resetTime
  };
}

function applyRateLimit(req, res, limitName, customIdentifier = null) {
  const config = rateLimitConfig[limitName];
  if (!config) {
    console.error(`[RATE_LIMIT] Unknown limit name: ${limitName}`);
    return { allowed: true, remaining: 999, resetTime: Date.now() + 60000 };
  }
  
  const identifier = customIdentifier || `${limitName}:${getClientIP(req)}`;
  const result = checkRateLimit(identifier, config.limit, config.windowMs);
  
  if (!result.allowed) {
    const retryAfter = Math.ceil((result.resetTime - Date.now()) / 1000);
    console.log(`[RATE_LIMIT] Violation: ${limitName} for ${identifier} - retry after ${retryAfter}s`);
    
    res.setHeader('Retry-After', String(retryAfter));
    res.setHeader('X-RateLimit-Limit', String(config.limit));
    res.setHeader('X-RateLimit-Remaining', '0');
    res.setHeader('X-RateLimit-Reset', String(Math.floor(result.resetTime / 1000)));
    
    res.writeHead(429, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      error: 'Too many requests',
      retryAfter: retryAfter,
      message: `Rate limit exceeded. Please try again in ${retryAfter} seconds.`
    }));
    return { allowed: false };
  }
  
  res.setHeader('X-RateLimit-Limit', String(config.limit));
  res.setHeader('X-RateLimit-Remaining', String(result.remaining));
  res.setHeader('X-RateLimit-Reset', String(Math.floor(result.resetTime / 1000)));
  
  return result;
}

function cleanupExpiredRateLimits() {
  const now = Date.now();
  let cleaned = 0;
  for (const [key, entry] of rateLimitStore.entries()) {
    if (entry.resetTime <= now) {
      rateLimitStore.delete(key);
      cleaned++;
    }
  }
  if (cleaned > 0) {
    console.log(`[RATE_LIMIT] Cleaned up ${cleaned} expired entries. Store size: ${rateLimitStore.size}`);
  }
}

setInterval(cleanupExpiredRateLimits, 60000);

// ========== END RATE LIMITING ==========

