async function handleEnrichRecall(req, res, requestId, recallId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);

  const user = await authenticateRequest(req);
  if (!user) {
    res.writeHead(401, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ success: false, error: 'Authentication required' }));
    return;
  }

  try {
    const supabase = getSupabaseClient();
    if (!supabase) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: false, error: 'Database not configured' }));
      return;
    }

    const { data: recall, error: fetchError } = await supabase
      .from('vehicle_recalls')
      .select('id, vehicle_id, component, summary, consequence, remedy, manufacturer, nhtsa_campaign_number')
      .eq('id', recallId)
      .single();

    if (fetchError || !recall) {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: false, error: 'Recall not found' }));
      return;
    }

    const { data: vehicle } = await supabase
      .from('vehicles')
      .select('id, owner_id')
      .eq('id', recall.vehicle_id)
      .single();

    if (!vehicle || vehicle.owner_id !== user.id) {
      const { data: profile } = await supabase
        .from('profiles')
        .select('role')
        .eq('id', user.id)
        .single();
      if (profile?.role !== 'admin') {
        res.writeHead(403, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: false, error: 'Access denied' }));
        return;
      }
    }

    let aiColumnsReady = false;
    const { data: aiRow, error: aiColErr } = await supabase
      .from('vehicle_recalls')
      .select('ai_summary, severity')
      .eq('id', recallId)
      .single();
    if (!aiColErr) {
      aiColumnsReady = true;
      if (aiRow?.ai_summary && aiRow?.severity) {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: true, ai_summary: aiRow.ai_summary, severity: aiRow.severity, cached: true }));
        return;
      }
    }

    if (!anthropicClient) {
      res.writeHead(503, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: false, error: 'AI service not available' }));
      return;
    }

    const prompt = `You are an automotive safety expert. A vehicle owner needs to understand an NHTSA recall. Rewrite it in plain English and rate its severity.

Recall details:
- Component: ${recall.component || 'Unknown'}
- Campaign: ${recall.nhtsa_campaign_number || 'N/A'}
- Manufacturer: ${recall.manufacturer || 'Unknown'}
- Summary: ${recall.summary || 'No summary available'}
- Consequence: ${recall.consequence || 'None stated'}
- Remedy: ${recall.remedy || 'None stated'}

Return ONLY valid JSON (no markdown, no code blocks):
{
  "plain_summary": "2-3 sentences: what is wrong, what could happen, what the owner should do",
  "severity": "critical|important|monitor",
  "severity_reason": "one short sentence explaining the severity rating"
}

Severity guide: critical = risk of injury/accident/fire; important = significant safety or functionality issue; monitor = minor issue, watch but not urgent.`;

    const aiResponse = await anthropicClient.messages.create({
      model: 'claude-3-5-haiku-20241022',
      max_tokens: 400,
      messages: [{ role: 'user', content: prompt }]
    });

    let aiSummary = null;
    let severity = 'monitor';

    try {
      const rawText = aiResponse.content[0]?.text?.trim() || '';
      const cleaned = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
      const parsed = JSON.parse(cleaned);
      if (parsed.plain_summary && typeof parsed.plain_summary === 'string') {
        aiSummary = parsed.plain_summary;
      }
      if (['critical', 'important', 'monitor'].includes(parsed.severity)) {
        severity = parsed.severity;
      }
    } catch {
      aiSummary = aiResponse.content[0]?.text?.trim() || null;
      severity = 'monitor';
    }

    if (aiSummary && aiColumnsReady) {
      const { error: updateErr } = await supabase
        .from('vehicle_recalls')
        .update({ ai_summary: aiSummary, severity })
        .eq('id', recallId);
      if (updateErr) {
        console.error(`[${requestId}] Failed to save recall enrichment:`, updateErr.message);
      }
    }

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ success: true, ai_summary: aiSummary, severity, cached: false }));

  } catch (error) {
    console.error(`[${requestId}] Enrich recall error:`, error);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ success: false, error: 'Something went wrong. Please try again later.' }));
  }
}

async function runRecallsAiMigration() {
  const supabase = getSupabaseClient();
  if (!supabase) return;
  const { error } = await supabase.from('vehicle_recalls').select('ai_summary, severity').limit(1);
  if (error && (error.code === '42703' || (error.message && error.message.includes('ai_summary')))) {
    console.warn('[Migration] vehicle_recalls ai_summary/severity columns missing. Run supabase/migrations/20260322_vehicle_recalls_ai_columns.sql in the Supabase SQL Editor to enable AI recall enrichment.');
  }
}

function startWeeklyRecallCheckScheduler() {
  console.log('Weekly recall check scheduler started');
  
  setInterval(async () => {
    const now = new Date();
    if (!lastRecallCheckTime || (now - lastRecallCheckTime) >= RECALL_CHECK_INTERVAL_MS) {
      console.log('Running scheduled weekly recall check...');
      lastRecallCheckTime = now;
      
      const supabase = getSupabaseClient();
      if (!supabase) return;
      
      try {
        const { data: checkLog } = await supabase
          .from('recall_check_log')
          .insert({
            check_type: 'scheduled',
            vehicles_checked: 0,
            recalls_found: 0,
            new_recalls_added: 0,
            started_at: now.toISOString()
          })
          .select()
          .single();
        
        const logId = checkLog?.id;
        
        const { data: vehicles } = await supabase
          .from('vehicles')
          .select('id, make, model, year')
          .not('make', 'is', null)
          .not('model', 'is', null)
          .not('year', 'is', null);
        
        let vehiclesChecked = 0;
        let totalRecallsFound = 0;
        let totalNewRecalls = 0;
        
        for (const vehicle of vehicles || []) {
          try {
            const result = await checkVehicleRecalls(vehicle.id, vehicle.make, vehicle.model, vehicle.year);
            vehiclesChecked++;
            totalRecallsFound += result.total_recalls;
            totalNewRecalls += result.new_recalls_added;
            await new Promise(resolve => setTimeout(resolve, 500));
          } catch (err) {
            console.error(`Scheduled recall check error for vehicle ${vehicle.id}:`, err.message);
          }
        }
        
        if (logId) {
          await supabase
            .from('recall_check_log')
            .update({
              vehicles_checked: vehiclesChecked,
              recalls_found: totalRecallsFound,
              new_recalls_added: totalNewRecalls,
              completed_at: new Date().toISOString()
            })
            .eq('id', logId);
        }
        
        console.log(`Scheduled recall check complete: ${vehiclesChecked} vehicles, ${totalNewRecalls} new recalls`);
      } catch (error) {
        console.error('Scheduled recall check failed:', error);
      }
    }
  }, 60 * 60 * 1000); // Check every hour if weekly interval has passed
}

