// ========== BACKGROUND VERIFICATION BADGE LOGIC ==========

async function recalculateBackgroundVerified(supabase, providerId) {
  try {
    const { data: teamMembers, error: teamError } = await supabase
      .from('provider_team_members')
      .select('id, user_id, role, status')
      .eq('provider_id', providerId)
      .eq('status', 'active')
      .neq('role', 'owner');

    if (teamError) {
      console.error(`[recalculateBackgroundVerified] Failed to get team members for provider ${providerId}:`, teamError);
      return { success: false, error: teamError.message };
    }

    const nonOwnerEmployees = teamMembers || [];
    
    if (nonOwnerEmployees.length === 0) {
      await supabase
        .from('provider_applications')
        .update({ 
          background_verified: false,
          background_verified_at: null
        })
        .eq('user_id', providerId);
      
      return { 
        success: true, 
        badgeEarned: false, 
        reason: 'No non-owner employees',
        totalEmployees: 0,
        verifiedEmployees: 0
      };
    }

    const employeeUserIds = nonOwnerEmployees.map(e => e.user_id);

    const { data: backgroundChecks, error: checksError } = await supabase
      .from('provider_background_checks')
      .select('id, employee_id, status, subject_type')
      .eq('provider_id', providerId)
      .eq('subject_type', 'employee')
      .in('employee_id', employeeUserIds);

    if (checksError) {
      console.error(`[recalculateBackgroundVerified] Failed to get background checks for provider ${providerId}:`, checksError);
      return { success: false, error: checksError.message };
    }

    const clearedStatuses = ['clear', 'eligible'];
    const clearedChecksByEmployee = new Map();
    
    for (const check of (backgroundChecks || [])) {
      if (clearedStatuses.includes(check.status)) {
        clearedChecksByEmployee.set(check.employee_id, check);
      }
    }

    const verifiedCount = clearedChecksByEmployee.size;
    const totalEmployees = nonOwnerEmployees.length;
    const allVerified = verifiedCount === totalEmployees;

    const updateData = {
      background_verified: allVerified,
      background_verified_at: allVerified ? new Date().toISOString() : null
    };

    await supabase
      .from('provider_applications')
      .update(updateData)
      .eq('user_id', providerId);

    console.log(`[recalculateBackgroundVerified] Provider ${providerId}: ${verifiedCount}/${totalEmployees} employees verified, badge=${allVerified}`);

    return {
      success: true,
      badgeEarned: allVerified,
      totalEmployees,
      verifiedEmployees: verifiedCount,
      pendingEmployeeIds: nonOwnerEmployees
        .filter(e => !clearedChecksByEmployee.has(e.user_id))
        .map(e => e.user_id)
    };

  } catch (error) {
    console.error(`[recalculateBackgroundVerified] Error for provider ${providerId}:`, error);
    return { success: false, error: error.message };
  }
}

// ========== BACKGROUNDCHECKS.COM API ==========
// Platform Integration: MCC is the platform, providers are customers,
// their employees are the background check subjects.
// Docs: https://backgroundchecks.com/developers/api
// Auth: BACKGROUNDCHECKS_TOKEN env var (api_token query param)
// Set BACKGROUNDCHECKS_ENV=production for live checks (default: sandbox)

function getBgChecksBaseUrl() {
  const env = process.env.BACKGROUNDCHECKS_ENV || 'sandbox';
  return env === 'production'
    ? 'https://www.backgroundchecks.com'
    : 'https://sandbox.backgroundchecks.com';
}

function getBgChecksToken() {
  return process.env.BACKGROUNDCHECKS_TOKEN || null;
}

async function bgChecksRequest(endpoint, method = 'GET', body = null) {
  const token = getBgChecksToken();
  if (!token) {
    throw new Error('BACKGROUNDCHECKS_TOKEN not configured');
  }

  const baseUrl = getBgChecksBaseUrl();
  const sep = endpoint.includes('?') ? '&' : '?';
  const url = `${baseUrl}/api/fact_token/${token}/${endpoint}${sep}app_token=${token}`;

  const options = {
    method,
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' }
  };

  if (body && method !== 'GET') {
    options.body = JSON.stringify(body);
  }

  const response = await fetch(url, options);
  let data;
  try {
    data = await response.json();
  } catch {
    data = {};
  }

  if (!response.ok) {
    throw new Error(data.message || data.error || `BackgroundChecks.com API error: ${response.status}`);
  }

  return data;
}

// Ensure the provider has a BackgroundChecks.com customer account.
// Stores the account_id in provider_background_check_accounts table (or returns cached).
async function ensureBgChecksAccount(supabase, providerId, providerEmail, providerName) {
  const { data: existing } = await supabase
    .from('provider_background_check_accounts')
    .select('bgchecks_account_id')
    .eq('provider_id', providerId)
    .single();

  if (existing?.bgchecks_account_id) {
    return existing.bgchecks_account_id;
  }

  const accountData = await bgChecksRequest('platform/accounts', 'POST', {
    email: providerEmail,
    name: providerName,
    external_id: `mcc_provider_${providerId}`
  });

  const accountId = accountData.id || accountData.account_id;
  if (!accountId) {
    throw new Error('BackgroundChecks.com did not return an account ID');
  }

  await supabase.from('provider_background_check_accounts').upsert({
    provider_id: providerId,
    bgchecks_account_id: accountId,
    created_at: new Date().toISOString()
  }, { onConflict: 'provider_id' });

  return accountId;
}

async function handleBgChecksInitiate(req, res, requestId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);

  const user = await enforce2fa(req, res, requestId);
  if (!user) return;

  let body = '';
  req.on('data', chunk => { body += chunk.toString(); });

  req.on('end', async () => {
    try {
      const parsed = JSON.parse(body);
      const { providerId, firstName, lastName, email, phone, city, state, zipcode, subjectType, employeeId, providerEmail, providerName } = parsed;

      if (!providerId || !firstName || !lastName || !email || !state) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Missing required fields: providerId, firstName, lastName, email, state' }));
        return;
      }

      const supabase = getSupabaseClient();
      if (!supabase) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Database not configured' }));
        return;
      }

      const apiToken = getBgChecksToken();

      if (!apiToken) {
        const { data: bgCheck, error: insertError } = await supabase
          .from('provider_background_checks')
          .insert({
            provider_id: providerId,
            employee_id: employeeId || null,
            subject_first_name: firstName,
            subject_last_name: lastName,
            subject_email: email,
            subject_type: subjectType || 'employee',
            work_location_state: state,
            work_location_city: city || null,
            status: 'initiated',
            package_slug: 'standard_criminal_mvr',
            api_provider: 'backgroundchecks'
          })
          .select()
          .single();

        if (insertError) {
          console.error(`[${requestId}] Failed to store background check:`, insertError);
          res.writeHead(500, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'Failed to save background check request' }));
          return;
        }

        console.log(`[${requestId}] Background check queued (BACKGROUNDCHECKS_TOKEN not set): ${bgCheck.id}`);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          success: true,
          checkId: bgCheck.id,
          status: 'initiated',
          message: 'Background check request saved. BackgroundChecks.com API key pending configuration.',
          apiConfigured: false
        }));
        return;
      }

      let bgchecksAccountId = null;
      try {
        bgchecksAccountId = await ensureBgChecksAccount(
          supabase, providerId,
          providerEmail || `provider_${providerId}@mcc.internal`,
          providerName || `Provider ${providerId}`
        );
        console.log(`[${requestId}] BackgroundChecks.com account: ${bgchecksAccountId}`);
      } catch (accErr) {
        console.error(`[${requestId}] Failed to get/create BgChecks account:`, accErr);
      }

      const orderPayload = {
        first_name: firstName,
        last_name: lastName,
        email: email,
        phone: phone || undefined,
        zip: zipcode || undefined,
        state: state,
        city: city || undefined,
        package: 'standard_criminal_mvr',
        external_id: `mcc_${subjectType || 'employee'}_${providerId}${employeeId ? '_' + employeeId : ''}`,
        copy_requested: true
      };

      const orderEndpoint = bgchecksAccountId
        ? `platform/accounts/${bgchecksAccountId}/orders`
        : 'orders';

      const order = await bgChecksRequest(orderEndpoint, 'POST', orderPayload);
      console.log(`[${requestId}] BackgroundChecks.com order created: ${order.id}`);

      const { data: bgCheck, error: insertError } = await supabase
        .from('provider_background_checks')
        .insert({
          provider_id: providerId,
          employee_id: employeeId || null,
          subject_first_name: firstName,
          subject_last_name: lastName,
          subject_email: email,
          subject_type: subjectType || 'employee',
          work_location_state: state,
          work_location_city: city || null,
          status: order.status || 'pending',
          package_slug: 'standard_criminal_mvr',
          api_provider: 'backgroundchecks',
          external_order_id: order.id,
          invitation_url: order.applicant_url || order.invitation_url || null,
          invitation_sent_at: new Date().toISOString()
        })
        .select()
        .single();

      if (insertError) {
        console.error(`[${requestId}] Failed to store background check record:`, insertError);
      }

      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        success: true,
        checkId: bgCheck?.id,
        orderId: order.id,
        status: order.status || 'pending',
        applicantUrl: order.applicant_url || order.invitation_url || null,
        apiConfigured: true
      }));

    } catch (error) {
      console.error(`[${requestId}] BackgroundChecks initiate error:`, error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to initiate background check. Please try again later.' }));
    }
  });
}

async function handleBgChecksWebhook(req, res, requestId) {
  setSecurityHeaders(res, true);

  const chunks = [];
  req.on('data', chunk => { chunks.push(chunk); });

  req.on('end', async () => {
    const rawBody = Buffer.concat(chunks).toString();

    try {
      const event = JSON.parse(rawBody);

      if (!event || !event.event) {
        console.warn(`[${requestId}] Invalid BackgroundChecks webhook: missing event`);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid webhook payload' }));
        return;
      }

      const eventType = event.event;
      const eventData = event.data || {};
      const orderId = eventData.id || eventData.order_id;

      console.log(`[${requestId}] BackgroundChecks.com webhook: ${eventType}, order: ${orderId}`);

      const supabase = getSupabaseClient();
      if (!supabase) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Database not configured' }));
        return;
      }

      let updateData = {};

      switch (eventType) {
        case 'order.created':
        case 'order.pending':
          updateData = { status: 'pending' };
          break;
        case 'order.processing':
          updateData = { status: 'processing' };
          break;
        case 'order.complete':
        case 'order.completed': {
          const bgResult = eventData.result || eventData.status_detail;
          let finalStatus = 'complete';
          if (bgResult === 'clear' || bgResult === 'eligible') finalStatus = 'eligible';
          else if (bgResult === 'consider' || bgResult === 'needs_review') finalStatus = 'needs_review';
          else if (bgResult === 'suspended') finalStatus = 'suspended';
          updateData = {
            status: finalStatus,
            result: bgResult || null,
            completed_at: new Date().toISOString(),
            report_url: eventData.report_url || eventData.report_widget_url || null
          };
          break;
        }
        case 'order.cancelled':
        case 'order.canceled':
          updateData = { status: 'canceled' };
          break;
        case 'order.disputed':
          updateData = { status: 'disputed' };
          break;
        case 'order.adverse_action':
          updateData = { status: 'not_eligible', adjudication_status: 'adverse_action' };
          break;
      }

      if (orderId && Object.keys(updateData).length > 0) {
        updateData.updated_at = new Date().toISOString();

        const { data: updated, error: updateError } = await supabase
          .from('provider_background_checks')
          .update(updateData)
          .eq('external_order_id', orderId)
          .select()
          .single();

        if (updateError) {
          console.error(`[${requestId}] Failed to update background check:`, updateError);
        } else if (updated) {
          console.log(`[${requestId}] Updated background check ${updated.id} → ${updateData.status || 'unchanged'}`);

          if (updateData.status === 'eligible' || updateData.status === 'clear') {
            if (updated.subject_type === 'provider') {
              await supabase
                .from('profiles')
                .update({
                  background_check_status: 'cleared',
                  background_check_cleared_at: new Date().toISOString(),
                  background_check_id: updated.id
                })
                .eq('id', updated.provider_id);
            }
          }

          if (updated.provider_id) {
            await recalculateBackgroundVerified(supabase, updated.provider_id);
          }
        }
      }

      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ received: true }));

    } catch (error) {
      console.error(`[${requestId}] BackgroundChecks webhook error:`, error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Webhook processing failed' }));
    }
  });
}

async function handleBgChecksStatus(req, res, requestId, providerId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);

  const user = await enforce2fa(req, res, requestId);
  if (!user) return;

  try {
    const supabase = getSupabaseClient();
    if (!supabase) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Database not configured' }));
      return;
    }

    const { data: checks, error } = await supabase
      .from('provider_background_checks')
      .select('*')
      .eq('provider_id', providerId)
      .order('created_at', { ascending: false });

    if (error) throw error;

    const apiToken = getBgChecksToken();
    const baseUrl = getBgChecksBaseUrl();

    const enriched = (checks || []).map(c => ({
      ...c,
      report_widget_url: c.external_order_id && apiToken
        ? `${baseUrl}/connect/report/${c.external_order_id}?app_token=${apiToken}`
        : c.report_url || null,
      api_configured: !!apiToken
    }));

    const providerCheck = enriched.find(c => c.subject_type === 'provider');
    const employeeChecks = enriched.filter(c => c.subject_type !== 'provider');

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      providerCheck: providerCheck || null,
      employeeChecks,
      totalChecks: enriched.length,
      clearedCount: enriched.filter(c => c.status === 'eligible' || c.status === 'clear').length,
      apiConfigured: !!apiToken
    }));

  } catch (error) {
    console.error(`[${requestId}] BgChecks status error:`, error);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Failed to fetch background check status' }));
  }
}

async function handleBgChecksReportUrl(req, res, requestId, checkId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);

  const user = await enforce2fa(req, res, requestId);
  if (!user) return;

  try {
    const supabase = getSupabaseClient();
    if (!supabase) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Database not configured' }));
      return;
    }

    const { data: check, error } = await supabase
      .from('provider_background_checks')
      .select('id, external_order_id, provider_id, report_url, status')
      .eq('id', checkId)
      .single();

    if (error || !check) {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Background check not found' }));
      return;
    }

    if (check.provider_id !== user.id) {
      res.writeHead(403, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Not authorized' }));
      return;
    }

    const apiToken = getBgChecksToken();
    const baseUrl = getBgChecksBaseUrl();

    let reportUrl = check.report_url;
    if (!reportUrl && check.external_order_id && apiToken) {
      reportUrl = `${baseUrl}/connect/report/${check.external_order_id}?app_token=${apiToken}`;
    }

    if (!reportUrl) {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Report not yet available. Check status must be complete.' }));
      return;
    }

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ reportUrl, checkId, status: check.status }));

  } catch (error) {
    console.error(`[${requestId}] BgChecks report URL error:`, error);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Failed to get report URL' }));
  }
}

async function handleProviderVerificationStatus(req, res, requestId, providerId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);
  
  if (req.method === 'OPTIONS') {
    res.writeHead(200);
    res.end();
    return;
  }

  const user = await enforce2fa(req, res, requestId);
  if (!user) return;

  try {
    const supabase = getSupabaseClient();
    if (!supabase) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Database not configured' }));
      return;
    }

    if (!isValidUUID(providerId)) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Invalid provider ID format' }));
      return;
    }

    // Authorization: Any team member can view their team's verification status
    const authorized = await isTeamMember(supabase, providerId, user.id);
    if (!authorized) {
      res.writeHead(403, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Forbidden: You do not have access to this provider\'s verification status' }));
      return;
    }

    const { data: teamMembers, error: teamError } = await supabase
      .from('provider_team_members')
      .select('id, user_id, role, status')
      .eq('provider_id', providerId)
      .eq('status', 'active')
      .neq('role', 'owner');

    if (teamError) {
      throw teamError;
    }

    const nonOwnerEmployees = teamMembers || [];
    
    if (nonOwnerEmployees.length === 0) {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        badgeEarned: false,
        totalEmployees: 0,
        verifiedEmployees: 0,
        pendingEmployees: [],
        isVoluntary: true,
        message: 'Add team members to start earning the verification badge'
      }));
      return;
    }

    const employeeUserIds = nonOwnerEmployees.map(e => e.user_id);

    const [checksResult, profilesResult] = await Promise.all([
      supabase
        .from('provider_background_checks')
        .select('id, employee_id, status, subject_type')
        .eq('provider_id', providerId)
        .eq('subject_type', 'employee')
        .in('employee_id', employeeUserIds),
      supabase
        .from('profiles')
        .select('id, full_name, email')
        .in('id', employeeUserIds)
    ]);

    if (checksResult.error) throw checksResult.error;
    if (profilesResult.error) throw profilesResult.error;

    const clearedStatuses = ['clear', 'eligible'];
    const clearedChecksByEmployee = new Map();
    
    for (const check of (checksResult.data || [])) {
      if (clearedStatuses.includes(check.status)) {
        clearedChecksByEmployee.set(check.employee_id, check);
      }
    }

    const profilesMap = new Map();
    for (const profile of (profilesResult.data || [])) {
      profilesMap.set(profile.id, profile);
    }

    const pendingEmployees = nonOwnerEmployees
      .filter(e => !clearedChecksByEmployee.has(e.user_id))
      .map(e => {
        const profile = profilesMap.get(e.user_id);
        return {
          id: e.user_id,
          name: profile?.full_name || profile?.email || 'Team Member',
          role: e.role
        };
      });

    const verifiedCount = clearedChecksByEmployee.size;
    const totalEmployees = nonOwnerEmployees.length;
    const badgeEarned = verifiedCount === totalEmployees && totalEmployees > 0;

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      badgeEarned,
      totalEmployees,
      verifiedEmployees: verifiedCount,
      pendingEmployees,
      isVoluntary: true
    }));

  } catch (error) {
    console.error(`[${requestId}] Provider verification status error:`, error);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Failed to fetch verification status' }));
  }
}

// ==================== PROVIDER TEAM MANAGEMENT API ====================

// Authorization helper: Check if user is any team member (owner, admin, or staff)
async function isTeamMember(supabaseAdmin, providerId, userId) {
  // Owner is always a member
  if (providerId === userId) return true;
  
  const { data } = await supabaseAdmin
    .from('provider_team_members')
    .select('role')
    .eq('provider_id', providerId)
    .eq('user_id', userId)
    .eq('status', 'active')
    .single();
  
  return !!data;
}

// Authorization helper: Check if user is team admin (owner or admin role)
async function isTeamAdmin(supabaseAdmin, providerId, userId) {
  // Owner is always admin
  if (providerId === userId) return true;
  
  const { data } = await supabaseAdmin
    .from('provider_team_members')
    .select('role')
    .eq('provider_id', providerId)
    .eq('user_id', userId)
    .eq('status', 'active')
    .in('role', ['owner', 'admin'])
    .single();
  
  return !!data;
}

async function handleGetProviderTeam(req, res, requestId, providerId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);
  
  if (req.method === 'OPTIONS') {
    res.writeHead(200);
    res.end();
    return;
  }
  
  const user = await enforce2fa(req, res, requestId);
  if (!user) return;

  try {
    if (!isValidUUID(providerId)) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Invalid provider ID format' }));
      return;
    }

    const supabase = getSupabaseClient();
    if (!supabase) {
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Database not configured' }));
      return;
    }

    // Authorization check
    const authorized = await isTeamAdmin(supabase, providerId, user.id);
    if (!authorized) {
      res.writeHead(403, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Forbidden: You do not have access to this provider team' }));
      return;
    }

    // Auto-initialize owner in team_members if they are the provider owner
    if (user.id === providerId) {
      await supabase
        .from('provider_team_members')
        .upsert({
          provider_id: providerId,
          user_id: providerId,
          role: 'owner',
          status: 'active'
        }, { onConflict: 'provider_id,user_id' });
    }

    const { data: teamMembers, error: teamError } = await supabase
      .from('provider_team_members')
      .select('id, provider_id, user_id, role, status, created_at, updated_at, invited_by')
      .eq('provider_id', providerId)
      .eq('status', 'active');

    if (teamError) {
      console.error(`[${requestId}] Get provider team error:`, teamError);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch team members' }));
      return;
    }

    const team = teamMembers || [];
    const enrichedTeam = [];
    for (const member of team) {
      const { data: profile } = await supabase
        .from('profiles')
        .select('full_name, email')
        .eq('id', member.user_id)
        .single();
      enrichedTeam.push({
        ...member,
        full_name: profile?.full_name || null,
        email: profile?.email || null
      });
    }

    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ team: enrichedTeam }));

  } catch (error) {
    console.error(`[${requestId}] Get provider team error:`, error);
    res.writeHead(500, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: 'Failed to fetch team members' }));
  }
}

async function handleSendTeamInvitation(req, res, requestId, providerId) {
  setSecurityHeaders(res, true);
  setCorsHeaders(res);
  
  if (req.method === 'OPTIONS') {
    res.writeHead(200);
    res.end();
    return;
  }
  
  const user = await enforce2fa(req, res, requestId);
  if (!user) return;

  let body = '';
  req.on('data', chunk => { body += chunk.toString(); });

  req.on('end', async () => {
    try {
      if (!isValidUUID(providerId)) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid provider ID format' }));
        return;
      }

      let parsed;
      try {
        parsed = JSON.parse(body);
      } catch (e) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid JSON' }));
        return;
      }

      const { email, role } = parsed;

      if (!email || !role) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Email and role are required' }));
        return;
      }

      if (!['admin', 'staff'].includes(role)) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Role must be admin or staff' }));
        return;
      }

      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(email)) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid email format' }));
        return;
      }

      const supabase = getSupabaseClient();
      if (!supabase) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Database not configured' }));
        return;
      }

      // Authorization check
      const authorized = await isTeamAdmin(supabase, providerId, user.id);
      if (!authorized) {
        res.writeHead(403, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Forbidden: You do not have permission to send invitations for this provider' }));
        return;
      }

      const { data: existingMember } = await supabase
        .from('profiles')
        .select('id')
        .eq('email', email.toLowerCase())
        .single();

      if (existingMember) {
        const { data: alreadyTeamMember } = await supabase
          .from('provider_team_members')
          .select('id')
          .eq('provider_id', providerId)
          .eq('user_id', existingMember.id)
          .single();

        if (alreadyTeamMember) {
          res.writeHead(409, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'This user is already a team member' }));
          return;
        }
      }

      const { data: existingInvite } = await supabase
        .from('provider_invitations')
        .select('id')
        .eq('provider_id', providerId)
        .eq('email', email.toLowerCase())
        .is('accepted_at', null)
        .gt('expires_at', new Date().toISOString())
        .single();

      if (existingInvite) {
        res.writeHead(409, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'A pending invitation already exists for this email' }));
        return;
      }

      const token = crypto.randomBytes(32).toString('hex');
      const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();

      const { data: invitation, error: insertError } = await supabase
        .from('provider_invitations')
        .insert({
          provider_id: providerId,
          email: email.toLowerCase(),
          role: role,
          token: token,
          invited_by: user.id,
          expires_at: expiresAt
        })
        .select()
        .single();

      if (insertError) {
        console.error(`[${requestId}] Failed to create invitation:`, insertError);
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Failed to create invitation' }));
        return;
      }

      const { data: provider } = await supabase
        .from('profiles')
        .select('business_name, full_name')
        .eq('id', providerId)
        .single();

      const providerName = provider?.business_name || provider?.full_name || 'A provider';
      const domain = process.env.REPLIT_DOMAINS?.split(',')[0] || 'mycarconcierge.com';
      const protocol = domain.includes('localhost') ? 'http' : 'https';
      const inviteLink = `${protocol}://${domain}/accept-invite.html?token=${token}`;

      const emailHtml = `
        <h2>You've Been Invited to Join a Team!</h2>
        <p>${providerName} has invited you to join their team on My Car Concierge as a <strong>${role}</strong>.</p>
        <p>Click the button below to accept this invitation:</p>
        <a href="${inviteLink}" class="button">Accept Invitation</a>
        <p style="margin-top: 20px; color: #6c757d; font-size: 14px;">
          This invitation will expire in 7 days. If you didn't expect this invitation, you can safely ignore this email.
        </p>
      `;

      const emailResult = await sendEmailNotification(
        email,
        email,
        `Team Invitation from ${providerName}`,
        emailHtml
      );

      console.log(`[${requestId}] Team invitation created for ${email} to provider ${providerId}, email sent: ${emailResult.sent}`);

      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        success: true,
        invitation_id: invitation.id,
        email_sent: emailResult.sent
      }));

    } catch (error) {
      console.error(`[${requestId}] Send team invitation error:`, error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to send invitation' }));
    }
  });
}

